import { Popover } from "@base-ui/react/popover";
import { CalendarBlank } from "@phosphor-icons/react";
import { motion } from "motion/react";
import * as React from "react";
import type { Matcher } from "react-day-picker";

import { cn } from "@/lib/utils";

import { Calendar } from "./calendar";

// ─── Tiny date helpers ──────────────────────────────────────────────────
//
// Standalone stand-ins for the app's internal `date-only` lib. All dates
// here are plain `Date` objects normalized to local noon (avoids DST
// off-by-one glitches when only the calendar day matters).

function buildDate(year: number, monthIndex: number, day: number): Date {
	return new Date(year, monthIndex, day, 12, 0, 0, 0);
}

function todayDate(): Date {
	const now = new Date();
	return buildDate(now.getFullYear(), now.getMonth(), now.getDate());
}

function addDays(date: Date, amount: number): Date {
	const next = buildDate(date.getFullYear(), date.getMonth(), date.getDate());
	next.setDate(next.getDate() + amount);
	return next;
}

function formatDate(date: Date): string {
	return date.toLocaleDateString("en-US", {
		month: "short",
		day: "numeric",
		year: "numeric",
	});
}

type PopoverAlign = React.ComponentProps<typeof Popover.Positioner>["align"];
type PopoverSide = React.ComponentProps<typeof Popover.Positioner>["side"];

type DatePickerVariant = "field" | "pill" | "inline";

export interface DatePickerPreset {
	readonly label: string;
	readonly getValue: (today: Date) => Date;
}

export interface DatePickerProps {
	value: Date | null | undefined;
	onChange: (value: Date | null) => void;
	placeholder?: string;
	ariaLabel?: string;
	id?: string;
	name?: string;
	disabled?: boolean;
	required?: boolean;
	invalid?: boolean;
	autoFocus?: boolean;
	/**
	 * Open the popover automatically when the component mounts. Useful when
	 * `DatePicker` is revealed by a parent edit-mode transition (inline/editable
	 * fields) so the calendar appears directly rather than requiring a second
	 * click on the trigger.
	 */
	autoOpen?: boolean;
	allowClear?: boolean;
	closeOnSelect?: boolean;
	variant?: DatePickerVariant;
	align?: PopoverAlign;
	side?: PopoverSide;
	className?: string;
	contentClassName?: string;
	onBlur?: React.FocusEventHandler<HTMLButtonElement>;
	onFocus?: React.FocusEventHandler<HTMLButtonElement>;
	onKeyDown?: React.KeyboardEventHandler<HTMLButtonElement>;
	/**
	 * Fires when the popover closes, regardless of cause (selection, Escape,
	 * outside click). Edit-mode wrappers use this instead of `onBlur` because
	 * focus legitimately shifts between trigger and popup during interaction —
	 * blur-based commits would spuriously exit edit mode on every focus hop.
	 */
	onClose?: () => void;
	formatValue?: (value: Date) => string;
	startMonth?: Date;
	endMonth?: Date;
	disabledDates?: Matcher | Matcher[];
	presets?: readonly DatePickerPreset[];
}

const DEFAULT_PRESETS: readonly DatePickerPreset[] = [
	{ label: "Today", getValue: (today) => today },
	{ label: "Tomorrow", getValue: (today) => addDays(today, 1) },
	{ label: "Next week", getValue: (today) => addDays(today, 7) },
];

// ─── Trigger styles ───────────────────────────────────────────────────
//
// Three variants share a vocabulary (height, icon, truncation, focus ring)
// but each is tuned for a concrete surface. Each variant's "open" state
// pulls toward the popup's design language (primary-tinted focus ring,
// lifted surface) so the trigger + popup read as one component.

const TRIGGER_BASE = cn(
	"font-ui relative inline-flex min-w-0 items-center gap-2 text-left text-foreground outline-none",
	"transition-[border-color,background-color,color,box-shadow] duration-150",
	"disabled:cursor-not-allowed disabled:opacity-50",
);

const TRIGGER_VARIANT_CLASS: Record<DatePickerVariant, string> = {
	field: cn(
		"h-9 w-full rounded-[8px] border border-border bg-secondary px-3 text-sm leading-5",
		"hover:border-foreground/12 hover:bg-background/80",
		"focus-visible:border-primary focus-visible:[box-shadow:0_0_0_3px_color-mix(in_srgb,var(--primary)_12%,transparent)]",
	),
	pill: cn(
		"h-8 min-w-[9.5rem] rounded-full border border-border/60 bg-card px-3 text-xs font-medium",
		"hover:border-foreground/15 hover:bg-muted",
		"focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
	),
	inline: cn(
		// Trigger sizes to its container (callers typically wrap with
		// `flex-1`/`w-full`). No hard min-width — avoids double truncation
		// in dense cells where the container is the real width authority.
		"h-8 rounded-[10px] border border-border/70 bg-background px-2.5 text-sm",
		"hover:border-foreground/15 hover:bg-accent/60",
		"focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
	),
};

const TRIGGER_OPEN_CLASS: Record<DatePickerVariant, string> = {
	field:
		"border-primary/45 bg-background [box-shadow:0_0_0_3px_color-mix(in_srgb,var(--primary)_12%,transparent)]",
	pill: "border-primary/50 bg-background [box-shadow:0_0_0_3px_color-mix(in_srgb,var(--primary)_12%,transparent)]",
	inline:
		"border-primary/45 bg-background [box-shadow:0_0_0_3px_color-mix(in_srgb,var(--primary)_12%,transparent)]",
};

// ─── DatePicker ───────────────────────────────────────────────────────

const DatePicker = React.forwardRef<HTMLButtonElement, DatePickerProps>(
	function DatePicker(
		{
			value,
			onChange,
			placeholder = "Select date",
			ariaLabel,
			id,
			name,
			disabled,
			required,
			invalid,
			autoFocus,
			autoOpen = false,
			allowClear = true,
			closeOnSelect = true,
			variant = "field",
			align = "start",
			side = "bottom",
			className,
			contentClassName,
			onBlur,
			onFocus,
			onKeyDown,
			onClose,
			formatValue = formatDate,
			startMonth,
			endMonth,
			disabledDates,
			presets = DEFAULT_PRESETS,
		}: DatePickerProps,
		ref,
	) {
		const selected = value ?? null;
		const today = todayDate();
		const [open, setOpen] = React.useState(autoOpen);
		const [month, setMonth] = React.useState<Date>(() => selected ?? today);

		const displayValue = selected ? formatValue(selected) : placeholder;
		const showClear = allowClear && selected != null;
		const hasFooter = presets.length > 0 || allowClear;

		const commitValue = React.useCallback(
			(next: Date | null) => {
				onChange(next);
				if (next) {
					setMonth(next);
					if (closeOnSelect) setOpen(false);
					return;
				}
				setMonth(today);
				setOpen(false);
			},
			[closeOnSelect, onChange, today],
		);

		return (
			<Popover.Root
				open={open}
				onOpenChange={(next) => {
					setOpen(next);
					if (next) {
						setMonth(selected ?? today);
					} else {
						onClose?.();
					}
				}}
			>
				<Popover.Trigger
					ref={ref}
					id={id}
					name={name}
					disabled={disabled}
					autoFocus={autoFocus}
					onBlur={onBlur}
					onFocus={onFocus}
					aria-label={ariaLabel ?? placeholder}
					aria-invalid={invalid ? "true" : undefined}
					aria-required={required ? "true" : undefined}
					render={
						<motion.button
							type="button"
							whileTap={disabled ? undefined : { scale: 0.985 }}
						/>
					}
					onKeyDown={(event) => {
						onKeyDown?.(event);
						if (event.defaultPrevented) return;
						if (!showClear) return;
						if (event.key !== "Backspace" && event.key !== "Delete") return;
						event.preventDefault();
						commitValue(null);
					}}
					className={(state) =>
						cn(
							TRIGGER_BASE,
							TRIGGER_VARIANT_CLASS[variant],
							invalid &&
								"border-destructive/55 focus-visible:border-destructive focus-visible:[box-shadow:0_0_0_3px_rgba(220,38,38,0.12)]",
							state.open && TRIGGER_OPEN_CLASS[variant],
							className,
						)
					}
				>
					<CalendarBlank
						aria-hidden
						className={cn(
							"size-4 shrink-0 text-muted-foreground transition-colors",
							open && "text-primary",
							selected && "text-foreground/70",
						)}
						weight={selected ? "fill" : "regular"}
					/>
					<span
						className={cn(
							"min-w-0 flex-1 truncate tabular-nums",
							!selected && "text-muted-foreground",
						)}
					>
						{displayValue}
					</span>
				</Popover.Trigger>

				<Popover.Portal>
					<Popover.Positioner
						side={side}
						align={align}
						sideOffset={8}
						collisionPadding={12}
						className="z-[70]"
					>
						<Popover.Popup
							render={
								<motion.div
									initial={{ opacity: 0, y: -4, scale: 0.985 }}
									animate={{ opacity: 1, y: 0, scale: 1 }}
									exit={{ opacity: 0, y: -3, scale: 0.99 }}
									transition={{ duration: 0.16, ease: [0.22, 1, 0.36, 1] }}
								/>
							}
							className={cn(
								"w-[17.5rem] origin-top overflow-hidden rounded-[16px] border border-border/70 bg-popover text-popover-foreground",
								"shadow-[0_1px_2px_rgba(15,23,42,0.06),0_18px_48px_-16px_rgba(15,23,42,0.22)]",
								"focus-visible:outline-none data-[starting-style]:opacity-0 data-[ending-style]:opacity-0",
								contentClassName,
							)}
						>
							<Calendar
								mode="single"
								month={month}
								onMonthChange={setMonth}
								selected={selected ?? undefined}
								onSelect={(next) => commitValue(next ?? null)}
								disabled={disabledDates}
								startMonth={startMonth}
								endMonth={endMonth}
							/>

							{hasFooter ? (
								<DatePickerFooter
									presets={presets}
									today={today}
									allowClear={allowClear}
									showClear={showClear}
									onPick={commitValue}
								/>
							) : null}
						</Popover.Popup>
					</Popover.Positioner>
				</Popover.Portal>
			</Popover.Root>
		);
	},
);

DatePicker.displayName = "DatePicker";

// ─── Footer ───────────────────────────────────────────────────────────

const FOOTER_BUTTON_BASE = cn(
	"font-ui inline-flex h-7 items-center justify-center gap-2 whitespace-nowrap rounded-[8px] px-2 text-[11px] font-medium outline-none",
	"transition-[background-color,color,scale] duration-150 active:scale-[0.96]",
	"focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
	"disabled:pointer-events-none disabled:cursor-default",
);

export interface DatePickerFooterProps {
	presets: readonly DatePickerPreset[];
	today: Date;
	allowClear: boolean;
	showClear: boolean;
	onPick: (next: Date | null) => void;
}

export function DatePickerFooter({
	presets,
	today,
	allowClear,
	showClear,
	onPick,
}: DatePickerFooterProps) {
	return (
		<div className="flex items-center gap-1 border-t border-border/60 px-2 py-1.5">
			{presets.map((preset) => (
				<button
					key={preset.label}
					type="button"
					className={cn(
						FOOTER_BUTTON_BASE,
						"text-foreground/80 hover:bg-[rgba(0,0,0,0.04)] hover:text-foreground",
					)}
					onClick={() => onPick(preset.getValue(today))}
				>
					{preset.label}
				</button>
			))}
			{allowClear ? (
				<button
					type="button"
					disabled={!showClear}
					className={cn(
						FOOTER_BUTTON_BASE,
						"ml-auto",
						showClear
							? "text-muted-foreground hover:bg-[rgba(0,0,0,0.04)] hover:text-foreground"
							: "text-muted-foreground/40",
					)}
					onClick={() => onPick(null)}
				>
					Clear
				</button>
			) : null}
		</div>
	);
}

export { DatePicker };

import { CaretDown, CaretLeft, CaretRight } from "@phosphor-icons/react";
import type * as React from "react";
import {
	type ChevronProps,
	DayPicker,
	type DayPickerProps,
	type DropdownProps,
	getDefaultClassNames,
	UI,
} from "react-day-picker";

import { cn } from "@/lib/utils";

// ─── Custom components ────────────────────────────────────────────────
//
// `react-day-picker` renders the grid as a real `<table>`:
//
//   MonthGrid → <table>
//   Weekdays  → <thead><tr>
//   Weekday   → <th>
//   Weeks     → <tbody>
//   Week      → <tr>
//   Day       → <td>                  (carries aria-selected / data-*)
//   DayButton → <button> inside <td>
//
// Applying flex to a <thead>/<tbody>/<tr> breaks column layout — columns
// clip, rows stack oddly. So the grid uses native `table-fixed w-full`
// and all modifier state is read from the `<td>` via group selectors.

/**
 * Month / year dropdown. A native `<select>` is kept (keyboard, native
 * menu, SR support, zero custom menu code) with a ghost-button surface —
 * the caption reads as one typographic unit instead of two form-field
 * chips. No app dropdown component is used, so this is fully
 * self-contained.
 */
function CalendarDropdown({
	value,
	onChange,
	options,
	className,
	disabled,
	"aria-label": ariaLabel,
}: DropdownProps) {
	return (
		<span className="relative inline-flex shrink-0 items-center">
			<select
				value={value}
				onChange={onChange}
				disabled={disabled}
				aria-label={ariaLabel}
				className={cn(
					"h-7 cursor-pointer appearance-none rounded-[8px] bg-transparent py-0 pl-2 pr-5 font-ui text-sm font-semibold tracking-tight text-foreground outline-none",
					"transition-colors hover:bg-muted focus-visible:bg-muted focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
					"disabled:pointer-events-none disabled:opacity-40",
					className,
				)}
			>
				{options?.map((option) => (
					<option
						key={option.value}
						value={option.value}
						disabled={option.disabled}
					>
						{option.label}
					</option>
				))}
			</select>
			<CaretDown
				aria-hidden
				weight="bold"
				className="pointer-events-none absolute right-1.5 size-3 text-muted-foreground"
			/>
		</span>
	);
}

function CalendarChevron({ orientation = "left", className }: ChevronProps) {
	if (orientation === "left") {
		return <CaretLeft className={className} weight="bold" />;
	}
	if (orientation === "right") {
		return <CaretRight className={className} weight="bold" />;
	}
	if (orientation === "down") {
		return <CaretDown className={className} weight="bold" />;
	}
	return <CaretDown className={cn("rotate-180", className)} weight="bold" />;
}

function Calendar({
	className,
	classNames,
	showOutsideDays = true,
	fixedWeeks = true,
	captionLayout = "dropdown",
	startMonth,
	endMonth,
	month,
	onMonthChange,
	...props
}: DayPickerProps) {
	const defaultClassNames = getDefaultClassNames();
	const today = new Date();
	const fallbackStartMonth = new Date(today.getFullYear() - 5, 0, 1);
	const fallbackEndMonth = new Date(today.getFullYear() + 5, 11, 31);

	// Power-user keyboard hooks layered on top of react-day-picker's default
	// arrow / PageUp / PageDown navigation. We only intercept keys the
	// library leaves free — never reassign its grid nav.
	//
	//   t, .             jump today's month into view
	//   Shift+PageUp     previous year
	//   Shift+PageDown   next year
	//
	// The wrapping <div> catches the events before they bubble out of the
	// calendar, but uses a single handler so nothing fires when the
	// calendar isn't focused.
	const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
		if (event.defaultPrevented) return;

		if (event.shiftKey && event.key === "PageUp") {
			event.preventDefault();
			const base = month ?? today;
			const next = new Date(base.getFullYear() - 1, base.getMonth(), 1, 12);
			onMonthChange?.(next);
			return;
		}

		if (event.shiftKey && event.key === "PageDown") {
			event.preventDefault();
			const base = month ?? today;
			const next = new Date(base.getFullYear() + 1, base.getMonth(), 1, 12);
			onMonthChange?.(next);
			return;
		}

		// Jump-to-today. Skip when typing into the month/year dropdowns
		// (`select` elements) so they keep their native first-letter search.
		const target = event.target as HTMLElement;
		const isEditableSurface =
			target.tagName === "SELECT" ||
			target.tagName === "INPUT" ||
			target.tagName === "TEXTAREA";
		if ((event.key === "t" || event.key === ".") && !isEditableSurface) {
			event.preventDefault();
			const now = new Date();
			onMonthChange?.(new Date(now.getFullYear(), now.getMonth(), 1, 12));
		}
	};

	// The wrapping div is a keyboard proxy, not an interactive control —
	// the real grid roles live inside <DayPicker>. `role="group"` keeps
	// the a11y tree honest (grouping of related controls) without
	// stealing focus or implying a custom widget.
	return (
		<div role="group" onKeyDown={handleKeyDown}>
			<DayPicker
				showOutsideDays={showOutsideDays}
				fixedWeeks={fixedWeeks}
				captionLayout={captionLayout}
				startMonth={startMonth ?? fallbackStartMonth}
				endMonth={endMonth ?? fallbackEndMonth}
				month={month}
				onMonthChange={onMonthChange}
				className={cn("select-none p-2.5", className)}
				classNames={{
					[UI.Root]: defaultClassNames[UI.Root],
					// Single month: Months is the positioning context for the
					// absolutely-placed Nav. For multi-month, consumers can
					// override with their own `classNames`.
					[UI.Months]: "relative flex flex-col gap-3 sm:flex-row sm:gap-5",
					[UI.Month]: "flex flex-col gap-2",
					[UI.MonthCaption]: "flex h-8 items-center pl-0.5 pr-[4.25rem]",
					[UI.Dropdowns]: "flex items-center gap-0.5",
					[UI.DropdownRoot]: "flex shrink-0",
					[UI.MonthsDropdown]: "min-w-[6.5rem]",
					[UI.YearsDropdown]: "min-w-[4.5rem]",
					[UI.CaptionLabel]:
						"font-ui text-sm font-semibold tracking-tight text-foreground",
					// Nav renders as a sibling of Month inside Months. Anchor it
					// absolutely to the top-right of Months so it sits in the
					// same visual row as the caption.
					[UI.Nav]: "absolute right-0 top-0 z-10 flex h-8 items-center gap-0.5",
					[UI.PreviousMonthButton]: cn(
						"inline-flex size-7 items-center justify-center rounded-[8px] text-muted-foreground",
						"transition-[background-color,color,scale] duration-150",
						"hover:bg-muted hover:text-foreground active:scale-[0.96]",
						"focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
						"disabled:pointer-events-none disabled:opacity-30",
					),
					[UI.NextMonthButton]: cn(
						"inline-flex size-7 items-center justify-center rounded-[8px] text-muted-foreground",
						"transition-[background-color,color,scale] duration-150",
						"hover:bg-muted hover:text-foreground active:scale-[0.96]",
						"focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
						"disabled:pointer-events-none disabled:opacity-30",
					),
					[UI.Chevron]: "size-3.5",
					// Real <table>. `table-fixed` gives equal columns regardless of
					// numeric width; `w-full` lets it fill the popup.
					[UI.MonthGrid]: "w-full border-collapse table-fixed",
					[UI.Weekdays]: "",
					[UI.Weekday]:
						"h-7 pb-1 text-center align-middle font-ui text-[10px] font-semibold uppercase tracking-[0.16em] text-muted-foreground/70",
					[UI.Weeks]: "",
					[UI.Week]: "",
					// Day is the <td>. It carries aria-selected / data-selected /
					// data-today / data-outside / data-disabled — we style the
					// nested <button> from here via `group-data-[…]/day:`.
					[UI.Day]: cn(
						"group/day px-0 py-0.5 text-center align-middle",
						// Modifier → button styling, from the td state
						"[&[data-today=true]>button]:text-primary",
						"[&[data-today=true]>button]:font-semibold",
						"[&[data-outside=true]>button]:text-muted-foreground/40",
						"[&[data-disabled=true]>button]:pointer-events-none",
						"[&[data-disabled=true]>button]:opacity-40",
					),
					// 36 px tile hits touch guidance without blowing grid rhythm.
					[UI.DayButton]: cn(
						"relative mx-auto inline-flex size-9 items-center justify-center rounded-[10px] font-ui text-[13px] font-medium text-foreground outline-none",
						"transition-[background-color,color,scale,box-shadow] duration-150",
						"hover:bg-muted",
						"focus-visible:z-10 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[var(--color-brand)]",
						"active:scale-[0.96]",
						// Selected state is projected from the parent <td>:
						"group-data-[selected=true]/day:bg-primary",
						"group-data-[selected=true]/day:!text-primary-foreground",
						"group-data-[selected=true]/day:font-semibold",
						"group-data-[selected=true]/day:shadow-[0_6px_14px_-8px_color-mix(in_srgb,var(--primary)_70%,transparent)]",
						"group-data-[selected=true]/day:hover:bg-primary",
					),
					...classNames,
				}}
				components={{
					Dropdown: CalendarDropdown,
					Chevron: CalendarChevron,
				}}
				{...props}
			/>
		</div>
	);
}

export { Calendar };

import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}
